// ---- CONFIG (single source of truth) ----
const DAYS_WINDOW     = 7;   // must match the Schedule Trigger cadence
const PER_SOURCE_CAP  = 6;   // max articles per feed — prevents source starvation

// Identify a feed's source from its XML so articles stay attributable
function detectSource(xml) {
  if (xml.includes('zapier.com')) return 'Zapier Blog';
  if (xml.includes('blog.n8n.io')) return 'n8n Blog';
  return 'Unknown Source';
}

// Strip CDATA wrappers, HTML tags, and decode common entities
function clean(str) {
  if (!str) return '';
  return str
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&apos;/g, "'").replace(/&#x27;/g, "'")
    .replace(/&#x2014;/g, '—').replace(/&#xA0;|&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Pull the first matching tag out of an <item> block
function tag(block, name) {
  const m = block.match(new RegExp(`<${name}[^>]*>([\\s\\S]*?)</${name}>`, 'i'));
  return m ? clean(m[1]) : '';
}

const cutoff = new Date(Date.now() - DAYS_WINDOW * 24 * 60 * 60 * 1000);
const articles = [];

for (const item of $input.all()) {
  const xml = item.json.data;
  if (typeof xml !== 'string' || !xml.includes('<item')) continue; // skip failed/empty feeds

  const source = detectSource(xml);
  const blocks = xml.match(/<item[\s\S]*?<\/item>/g) || [];

  for (const block of blocks) {
    const pubDate = tag(block, 'pubDate');
    const published = new Date(pubDate);
    if (isNaN(published) || published < cutoff) continue;  // 7-day window

    articles.push({
      source,
      title: tag(block, 'title'),
      link: tag(block, 'link'),
      // truncate: RSS descriptions vary wildly in length; cap token spend
      summary: tag(block, 'description').slice(0, 400),
      published: published.toISOString(),
      publishedReadable: published.toUTCString().slice(0, 16),
    });
  }
}

// Dedupe by link (same story can appear in both feeds)
const seen = new Set();
const unique = articles.filter(a => {
  if (!a.link || seen.has(a.link)) return false;
  seen.add(a.link);
  return true;
});

// Newest first
unique.sort((a, b) => new Date(b.published) - new Date(a.published));

// Fair allocation: cap PER SOURCE so a high-volume feed can't crowd out a quieter one
const bySource = {};
const finalList = [];
for (const a of unique) {
  bySource[a.source] = (bySource[a.source] || 0) + 1;
  if (bySource[a.source] <= PER_SOURCE_CAP) finalList.push(a);
}
finalList.sort((a, b) => new Date(b.published) - new Date(a.published));

// Build one combined text blob for the AI node
const combinedText = finalList
  .map((a, i) => `${i + 1}. [${a.source}] ${a.title}\n   Published: ${a.publishedReadable}\n   ${a.summary}\n   URL: ${a.link}`)
  .join('\n\n');

return [{
  json: {
    articleCount: finalList.length,
    sourcesFound: [...new Set(finalList.map(a => a.source))],
    perSourceCounts: bySource,
    windowDays: DAYS_WINDOW,
    articles: finalList,
    combinedText: combinedText || 'No new articles were published in the last 7 days.',
  },
}];

// ---- INPUT ----
// The LLM node returns a JSON *string* in .text — parse it defensively.
const raw = $input.first().json.text || '';

// Pull upstream stats so the digest can report on its own coverage
const parsed = $('Parse, Filter & Dedupe').first().json;

let ai;
try {
  // Strip markdown fences if the model wrapped the JSON despite instructions
  const cleaned = raw.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = null;
}

// ---- FALLBACK: if the AI output is unusable, still ship something ----
if (!ai || !Array.isArray(ai.takeaways) || ai.takeaways.length === 0) {
  const fallback = [
    `# Competitor News Digest`,
    `**Week ending ${new Date().toUTCString().slice(0, 16)}**`,
    ``,
    `> The AI summarization step did not return usable output this week.`,
    `> Raw article list is included below so the digest is still actionable.`,
    ``,
    `## Articles Found (${parsed.articleCount})`,
    ...parsed.articles.map(a => `- **[${a.source}]** [${a.title}](${a.link}) — _${a.publishedReadable}_`),
  ].join('\n');

  return [{
    json: {
      subject: `[Degraded] Competitor Digest — ${new Date().toUTCString().slice(0, 16)}`,
      digestMarkdown: fallback,
      status: 'ai_failed',
    },
  }];
}

// ---- VALIDATION: never trust the model for anything we can compute ----
// Rebuild sources_covered from the takeaways themselves.
const citedSources = [...new Set(ai.takeaways.map(t => t.source).filter(Boolean))];

// Which sources had articles but got no takeaway? Report the gap honestly.
const allSources = Object.keys(parsed.perSourceCounts || {});
const uncovered = allSources.filter(s => !citedSources.includes(s));

// ---- BUILD MARKDOWN ----
const weekEnding = new Date().toUTCString().slice(0, 16);
const lines = [];

lines.push(`# Competitor News Digest`);
lines.push(`**Week ending ${weekEnding}**`);
lines.push('');

if (ai.headline) {
  lines.push(`### ${ai.headline}`);
  lines.push('');
}

lines.push(`## Key Takeaways`);
lines.push('');

ai.takeaways.forEach((t, i) => {
  lines.push(`**${i + 1}. ${t.title}**`);
  lines.push('');
  lines.push(t.insight);
  if (t.url) lines.push(`[Read more](${t.url}) · _${t.source}_`);
  lines.push('');
});

// ---- COVERAGE FOOTER: transparency about what was scanned ----
lines.push(`---`);
lines.push(`## Coverage`);
lines.push('');
lines.push(`Scanned **${allSources.length}** sources over the last **${parsed.windowDays}** days.`);
lines.push('');
Object.entries(parsed.perSourceCounts || {}).forEach(([src, count]) => {
  const flag = citedSources.includes(src) ? '' : ' _(no significant news)_';
  lines.push(`- **${src}**: ${count} article${count === 1 ? '' : 's'} published${flag}`);
});
lines.push('');
lines.push(`_${parsed.articleCount} articles analyzed. Generated automatically by n8n._`);

const digestMarkdown = lines.join('\n');

return [{
  json: {
    subject: `Competitor Digest — ${weekEnding}`,
    digestMarkdown,
    takeawayCount: ai.takeaways.length,
    sourcesCovered: citedSources,   // computed, not model-reported
    sourcesUncovered: uncovered,
    status: 'ok',
  },
}];
